"""Синусоидальный сигнал."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _check_below_nyquist, _time_axis_PHASE_MIN = -2.0 * np.pi_PHASE_MAX = 2.0 * np.piclass SineSignal(BaseSignal):    name = "Синусоидальный сигнал"    description = "Гармонический сигнал одной частоты: A·sin(2π·f·t + φ)."    params_schema = {        "amplitude": {"type": "float", "default": 1.0, "min": 0.0, "max": 1.0e6,                      "label": "Амплитуда", "units": "В"},        "frequency": {"type": "float", "default": 50.0, "min": 1.0e-6, "max": 1.0e6,                      "label": "Частота", "units": "Гц"},        "phase":     {"type": "float", "default": 0.0,                      "min": _PHASE_MIN, "max": _PHASE_MAX,                      "label": "Начальная фаза", "units": "рад"},        "duration":  {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                      "label": "Длительность", "units": "с"},        "fs":        {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                      "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        _check_below_nyquist("frequency", p["frequency"], p["fs"])        t = _time_axis(p["duration"], p["fs"])        x = p["amplitude"] * np.sin(2.0 * np.pi * p["frequency"] * t + p["phase"])        return t, x